import React, { createContext, useContext } from 'react';
import { Button } from '@/components/atoms/Button';
import { ArrowLeft } from '@untitledui/icons';
import { cx } from '@/utils/cx';
import { WithDataId } from '@/types/withDataId';

const defaultStyles = {
  gridTemplateAreas:
    "[grid-template-areas:'back_back'_'header_header'_'divider_divider'_'content_actions']",
  padding: 'px-6 pt-3',
  backNavigationClassName: 'hover:bg-transparent pl-0',
  withDivider: true,
  actionsStyles: '',
};

const variants = {
  primary: {
    ...defaultStyles,
    actionsStyles:
      'border-b border-secondary w-full h-full flex justify-end items-center',
  },
  secondary: {
    ...defaultStyles,
    gridTemplateAreas:
      "[grid-template-areas:'back_back'_'header_header'_'subHeader_actions'_'divider_divider'_'content_content']",
  },
  tertiary: {
    ...defaultStyles,
    gridTemplateAreas:
      "[grid-template-areas:'back_topActions'_'header_header'_'subHeader_actions']",
    padding: 'px-6 py-3',
    backNavigationClassName: 'hover:bg-transparent p-0',
    withDivider: false,
  },
  quaternary: {
    ...defaultStyles,
    gridTemplateAreas: "[grid-template-areas:'back_back'_'header_actions']",
    padding: 'px-6 py-3',
    withDivider: false,
  },
};

const PageHeaderContext = createContext(variants.primary);

type BackNavigationProps = {
  name: string;
  onClick: () => void;
} & WithDataId &
  Omit<React.ComponentProps<'div'>, 'onClick'>;

function BackNavigation({
  name,
  onClick,
  'data-id': dataId,
  ...rest
}: BackNavigationProps) {
  const { backNavigationClassName } = useContext(PageHeaderContext);
  return (
    <div
      className="[grid-area:back]"
      {...rest}
    >
      <Button
        className={backNavigationClassName}
        color="tertiary"
        iconLeading={ArrowLeft}
        onClick={onClick}
        data-id={dataId}
      >
        {name}
      </Button>
    </div>
  );
}

type HeaderProps = {
  children: string | React.ReactNode;
} & React.HTMLAttributes<HTMLElement>;

function Header({ children, className, ...rest }: HeaderProps) {
  if (typeof children === 'string') {
    return (
      <h1
        className={cx(
          '[grid-area:header] text-xl font-semibold text-primary lg:text-display-xs pb-1 overflow-hidden text-ellipsis whitespace-nowrap',
          className,
        )}
        {...rest}
      >
        {children}
      </h1>
    );
  }
  return (
    <div
      className={cx('[grid-area:header] pb-1', className)}
      {...rest}
    >
      {children}
    </div>
  );
}

type SubHeaderProps = {
  children: string | React.ReactNode;
} & React.HTMLAttributes<HTMLElement>;

function SubHeader({ children, ...rest }: SubHeaderProps) {
  if (typeof children === 'string') {
    return (
      <p
        className="[grid-area:subHeader] text-md text-tertiary flex items-end overflow-hidden text-ellipsis whitespace-nowrap"
        {...rest}
      >
        {children}
      </p>
    );
  }
  return (
    <div
      className="[grid-area:subHeader] flex gap-3 items-end flex-wrap"
      {...rest}
    >
      {children}
    </div>
  );
}

export interface PageHeaderProps extends React.ComponentProps<'header'> {
  variant?: 'primary' | 'secondary' | 'tertiary' | 'quaternary';
  children: React.ReactNode;
  className?: string;
  withDivider?: boolean;
}

export function PageHeader({
  variant = 'primary',
  children,
  className = '',
  withDivider,
  ...rest
}: PageHeaderProps) {
  const variantConfig = variants[variant];
  const { gridTemplateAreas, padding } = variantConfig;
  const showDivider =
    withDivider !== undefined ? withDivider : variantConfig.withDivider;

  return (
    <PageHeaderContext.Provider value={variantConfig}>
      <header
        className={cx('grid', padding, gridTemplateAreas, className)}
        {...rest}
      >
        {children}
        {showDivider && <Divider />}
      </header>
    </PageHeaderContext.Provider>
  );
}

function Divider() {
  return <div className="[grid-area:divider] border-t border-secondary mt-2" />;
}

type ActionsProps = {
  children?: React.ReactNode;
  className?: string;
} & React.ComponentProps<'div'>;

function Actions({ children, className = '', ...rest }: ActionsProps) {
  const { actionsStyles } = useContext(PageHeaderContext);

  return (
    <div
      className={cx(
        '[grid-area:actions] [justify-self:end] self-end',
        actionsStyles,
        className,
      )}
      {...rest}
    >
      <div className="flex gap-3">{children}</div>
    </div>
  );
}

type TopActionsProps = {
  children?: React.ReactNode;
} & React.ComponentProps<'div'>;

function TopActions({ children, ...rest }: TopActionsProps) {
  return (
    <div
      className="[grid-area:topActions] [justify-self:end] self-end"
      {...rest}
    >
      <div className="flex gap-3">{children}</div>
    </div>
  );
}

type ContentProps = {
  children?: React.ReactNode;
  className?: string;
} & React.ComponentProps<'div'>;

function Content({ children, className, ...rest }: ContentProps) {
  return (
    <div
      className={cx('[grid-area:content]', className)}
      {...rest}
    >
      {children}
    </div>
  );
}

PageHeader.BackNavigation = BackNavigation;
PageHeader.Header = Header;
PageHeader.SubHeader = SubHeader;
PageHeader.Actions = Actions;
PageHeader.TopActions = TopActions;
PageHeader.Content = Content;
